import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple


def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: Optional[list] = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS384', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (decoded_payload, header)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    # Get header without verification
    header = jwt.get_unverified_header(token)
    
    if verify and secret:
        # Verify and decode
        payload = jwt.decode(token, secret, algorithms=algorithms)
    else:
        # Decode without verification (for debugging)
        payload = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    
    return payload, header


def inspect_jwt(token: str, secret: Optional[str] = None, verify: bool = False,
                algorithms: Optional[list] = None, verbose: bool = True) -> Dict[str, Any]:
    """
    Inspect a JWT token and return detailed information.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature
        algorithms: List of allowed algorithms
        verbose: Print detailed information
    
    Returns:
        Dictionary containing token information
    """
    result = {
        'valid': False,
        'header': None,
        'payload': None,
        'expired': None,
        'errors': []
    }
    
    try:
        payload, header = decode_jwt(token, secret, verify, algorithms)
        result['header'] = header
        result['payload'] = payload
        result['valid'] = True
        
        # Check expiration
        if 'exp' in payload:
            exp_timestamp = payload['exp']
            exp_datetime = datetime.fromtimestamp(exp_timestamp)
            result['expired'] = exp_datetime < datetime.now()
            result['expiration_time'] = exp_datetime.isoformat()
        
        # Check issued at
        if 'iat' in payload:
            iat_timestamp = payload['iat']
            iat_datetime = datetime.fromtimestamp(iat_timestamp)
            result['issued_at'] = iat_datetime.isoformat()
        
        # Check not before
        if 'nbf' in payload:
            nbf_timestamp = payload['nbf']
            nbf_datetime = datetime.fromtimestamp(nbf_timestamp)
            result['not_before'] = nbf_datetime.isoformat()
        
    except jwt.ExpiredSignatureError as e:
        result['errors'].append(f'Token expired: {str(e)}')
        result['expired'] = True
        # Still try to decode without verification to see contents
        try:
            payload, header = decode_jwt(token, verify=False)
            result['header'] = header
            result['payload'] = payload
        except Exception:
            pass
            
    except jwt.InvalidSignatureError as e:
        result['errors'].append(f'Invalid signature: {str(e)}')
        # Still try to decode without verification
        try:
            payload, header = decode_jwt(token, verify=False)
            result['header'] = header
            result['payload'] = payload
        except Exception:
            pass
            
    except jwt.DecodeError as e:
        result['errors'].append(f'Decode error: {str(e)}')
        
    except jwt.InvalidTokenError as e:
        result['errors'].append(f'Invalid token: {str(e)}')
        
    except Exception as e:
        result['errors'].append(f'Unexpected error: {str(e)}')
    
    if verbose:
        print_jwt_info(result)
    
    return result


def print_jwt_info(info: Dict[str, Any]) -> None:
    """Print formatted JWT information."""
    print("\n" + "="*60)
    print("JWT TOKEN INSPECTION")
    print("="*60)
    
    if info['errors']:
        print("\n⚠️  ERRORS:")
        for error in info['errors']:
            print(f"  - {error}")
    
    if info['valid']:
        print("\n✓ Token Status: VALID")
    else:
        print("\n✗ Token Status: INVALID")
    
    if info['expired'] is not None:
        if info['expired']:
            print("✗ Expiration: EXPIRED")
        else:
            print("✓ Expiration: VALID")
    
    if info['header']:
        print("\n📋 HEADER:")
        print(json.dumps(info['header'], indent=2))
    
    if info['payload']:
        print("\n📦 PAYLOAD:")
        print(json.dumps(info['payload'], indent=2, default=str))
    
    if 'expiration_time' in info:
        print(f"\n⏰ Expiration Time: {info['expiration_time']}")
    
    if 'issued_at' in info:
        print(f"📅 Issued At: {info['issued_at']}")
    
    if 'not_before' in info:
        print(f"🔒 Not Before: {info['not_before']}")
    
    print("\n" + "="*60 + "\n")


def quick_decode(token: str) -> None:
    """Quick decode without verification - for rapid debugging."""
    inspect_jwt(token, verify=False)


def verify_token(token: str, secret: str, algorithms: Optional[list] = None) -> None:
    """Decode and verify token with secret."""
    inspect_jwt(token, secret=secret, verify=True, algorithms=algorithms)


